import React, { useState, useContext } from 'react';
import { Link } from 'react-router-dom';
import { FaThumbsUp, FaRegThumbsUp, FaBookmark, FaRegBookmark, FaComment, FaShare, FaEllipsisV } from 'react-icons/fa';
import { toast } from 'react-toastify';
import { AuthContext } from '../context/AuthContext';
import forumService from '../services/forumService';
import formatDate from '../utils/formatDate';

const ForumPostCard = ({ post, onUpdate }) => {
  const { user } = useContext(AuthContext);
  const [isLiked, setIsLiked] = useState(post.isLiked);
  const [isBookmarked, setIsBookmarked] = useState(post.isBookmarked);
  const [likesCount, setLikesCount] = useState(post.likesCount);
  const [showDropdown, setShowDropdown] = useState(false);

  const handleLike = async () => {
    if (!user) {
      toast.error('Please log in to like posts');
      return;
    }

    try {
      const response = await forumService.toggleLike(post._id);
      setIsLiked(response.isLiked);
      setLikesCount(response.likesCount);
      onUpdate && onUpdate();
    } catch (error) {
      toast.error('Failed to like post');
    }
  };

  const handleBookmark = async () => {
    if (!user) {
      toast.error('Please log in to bookmark posts');
      return;
    }

    try {
      const response = await forumService.toggleBookmark(post._id);
      setIsBookmarked(response.isBookmarked);
      onUpdate && onUpdate();
    } catch (error) {
      toast.error('Failed to bookmark post');
    }
  };

  const handleShare = () => {
    navigator.clipboard.writeText(`${window.location.origin}/forum/${post._id}`)
      .then(() => toast.success('Link copied to clipboard'))
      .catch(() => toast.error('Failed to copy link'));
  };

  const handleDelete = async () => {
    if (!user || user._id !== post.author._id) {
      toast.error('You do not have permission to delete this post');
      return;
    }

    try {
      await forumService.deletePost(post._id);
      toast.success('Post deleted successfully');
      onUpdate && onUpdate();
    } catch (error) {
      toast.error('Failed to delete post');
    }
  };

  return (
    <div className="bg-white rounded-lg shadow-md p-4 mb-4 border border-gray-100 hover:shadow-lg transition duration-300">
      <div className="flex justify-between items-start mb-2">
        <div className="flex items-center">
          <img
            src={post.author.profileImage || 'https://via.placeholder.com/40'}
            alt={post.author.name}
            className="w-10 h-10 rounded-full mr-3"
          />
          <div>
            <h3 className="font-semibold text-gray-800">{post.author.name}</h3>
            <p className="text-xs text-gray-500">{formatDate(post.createdAt, { includeRelativeTime: true })}</p>
          </div>
        </div>
        <div className="relative">
          <button 
            className="text-gray-500 hover:text-gray-800" 
            onClick={() => setShowDropdown(!showDropdown)}
          >
            <FaEllipsisV />
          </button>
          {showDropdown && (
            <div className="absolute right-0 mt-2 w-48 bg-white rounded-md shadow-lg z-10 border border-gray-200">
              {user && user._id === post.author._id && (
                <>
                  <Link 
                    to={`/forum/edit/${post._id}`} 
                    className="block px-4 py-2 text-sm text-gray-700 hover:bg-gray-100"
                  >
                    Edit Post
                  </Link>
                  <button 
                    onClick={handleDelete} 
                    className="block w-full text-left px-4 py-2 text-sm text-red-600 hover:bg-gray-100"
                  >
                    Delete Post
                  </button>
                </>
              )}
              <button 
                onClick={handleShare} 
                className="block w-full text-left px-4 py-2 text-sm text-gray-700 hover:bg-gray-100"
              >
                Share Post
              </button>
              <button 
                className="block w-full text-left px-4 py-2 text-sm text-gray-700 hover:bg-gray-100"
                onClick={() => setShowDropdown(false)}
              >
                Close
              </button>
            </div>
          )}
        </div>
      </div>

      <Link to={`/forum/${post._id}`}>
        <h2 className="text-xl font-bold text-gray-900 mb-2 hover:text-green-600">{post.title}</h2>
        <p className="text-gray-700 mb-3">
          {post.content.length > 200 
            ? post.content.substring(0, 200) + '...' 
            : post.content}
        </p>
        {post.image && (
          <div className="mb-3">
            <img 
              src={post.image} 
              alt={post.title} 
              className="rounded-lg max-h-60 w-auto" 
            />
          </div>
        )}
      </Link>

      <div className="flex justify-between items-center pt-3 border-t border-gray-200">
        <div className="flex space-x-4">
          <button 
            className="flex items-center text-gray-500 hover:text-blue-600"
            onClick={handleLike}
          >
            {isLiked ? <FaThumbsUp className="text-blue-600" /> : <FaRegThumbsUp />}
            <span className="ml-1">{likesCount}</span>
          </button>
          
          <Link to={`/forum/${post._id}`} className="flex items-center text-gray-500 hover:text-green-600">
            <FaComment />
            <span className="ml-1">{post.commentsCount}</span>
          </Link>
        </div>
        
        <div className="flex space-x-3">
          <button 
            className="text-gray-500 hover:text-yellow-600"
            onClick={handleBookmark}
          >
            {isBookmarked ? <FaBookmark className="text-yellow-600" /> : <FaRegBookmark />}
          </button>
          
          <button 
            className="text-gray-500 hover:text-purple-600"
            onClick={handleShare}
          >
            <FaShare />
          </button>
        </div>
      </div>

      {post.tags && post.tags.length > 0 && (
        <div className="mt-3 flex flex-wrap gap-2">
          {post.tags.map((tag, index) => (
            <span 
              key={index} 
              className="px-2 py-1 bg-green-100 text-green-800 text-xs rounded-full"
            >
              #{tag}
            </span>
          ))}
        </div>
      )}
    </div>
  );
};

export default ForumPostCard;
